import { useState } from 'react';
import { Check, Mail, ShieldCheck } from 'lucide-react';

export function MultiStepRegistration() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [step, setStep] = useState(1);

  const isEmailValid = email.includes("@") && email.includes(".");
  const isPasswordValid = password.length >= 8;

  return (
    <div className="w-full max-w-md mx-auto border border-border bg-card text-card-foreground p-8 rounded-2xl shadow-xl">
      {/* Logo & Header */}
      <div className="text-center mb-8">
        <div className="inline-flex h-12 w-12 items-center justify-center rounded-xl bg-primary/10 border border-primary/20 text-primary mb-4">
          <ShieldCheck className="h-6 w-6" />
        </div>
        <h3 className="text-2xl font-bold tracking-tight">Create Account</h3>
        <p className="text-sm text-muted-foreground mt-1">Setup your credentials to initialize build.</p>
      </div>

      {/* Visual Form Panels */}
      <div className="space-y-4">
        {step === 1 && (
          <div className="space-y-4">
            <label className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Email Address</label>
            <div className="relative flex items-center border border-border focus-within:border-primary/80 focus-within:ring-2 focus-within:ring-primary/20 rounded-xl bg-background px-3 py-2.5 transition-all">
              <Mail className="h-4.5 w-4.5 text-muted-foreground shrink-0 mr-3" />
              <input 
                type="email" 
                value={email} 
                onChange={(e) => setEmail(e.target.value)} 
                placeholder="name@domain.com" 
                className="w-full bg-transparent text-sm focus:outline-none text-foreground"
              />
            </div>
            <button 
              disabled={!isEmailValid}
              onClick={() => setStep(2)}
              className="w-full py-3 px-4 rounded-xl text-sm font-semibold bg-primary hover:bg-primary/95 text-primary-foreground transition-all disabled:opacity-50"
            >
              Continue
            </button>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-4">
            <label className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Choose Secure Password</label>
            <div className="relative flex items-center border border-border focus-within:border-primary/80 focus-within:ring-2 focus-within:ring-primary/20 rounded-xl bg-background px-3 py-2.5 transition-all">
              <input 
                type="password" 
                value={password} 
                onChange={(e) => setPassword(e.target.value)} 
                placeholder="••••••••" 
                className="w-full bg-transparent text-sm focus:outline-none text-foreground"
              />
            </div>
            <ul className="text-xs text-muted-foreground space-y-2 mt-2 font-mono">
              <li className="flex items-center gap-2">
                <Check className={`h-4 w-4 ${isPasswordValid ? 'text-emerald-500' : 'text-neutral-500'}`} />
                <span>At least 8 characters long</span>
              </li>
            </ul>
            <button 
              disabled={!isPasswordValid}
              onClick={() => setStep(3)}
              className="w-full py-3 px-4 rounded-xl text-sm font-semibold bg-primary hover:bg-primary/95 text-primary-foreground transition-all disabled:opacity-50"
            >
              Create Credentials
            </button>
          </div>
        )}

        {step === 3 && (
          <div className="text-center py-6 space-y-4 animate-pulse">
            <div className="inline-flex h-10 w-10 items-center justify-center rounded-full bg-emerald-500/10 text-emerald-500 border border-emerald-500/20 mb-2">
              <Check className="h-5 w-5" />
            </div>
            <h4 className="font-bold text-foreground">Registration Successful</h4>
            <p className="text-xs text-muted-foreground">Verification confirmation sent to {email}.</p>
          </div>
        )}
      </div>
    </div>
  );
}
